          <form onSubmit={handleSubmit} className="flex flex-col sm:flex-row gap-3 max-w-md mx-auto">
            <input
              type="email"
              placeholder="work@organization.com"
              className="flex-1 bg-gray-900 border border-gray-800 text-white placeholder:text-gray-500 px-4 py-3 rounded-lg focus:outline-none focus:border-blue-600 transition-colors"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              required
            />
            <button
              type="submit"
              disabled={loading}
              className="bg-white text-black font-medium px-6 py-3 rounded-lg hover:bg-gray-200 transition-all disabled:opacity-50 active:scale-95 shadow-sm hover:shadow-lg"
            >
              {loading ? "Processing..." : "Request Pilot"}
            </button>
          </form>
        )}

        <div className="text-xs text-gray-600 mt-8">
          SOC2 Compliant & ISO 27001 Certified
        </div>
      </div>
    </section>
  );
};

