import React, { useState, useEffect } from 'react';
import { Search } from 'lucide-react';

export const Navbar: React.FC = () => {
  const [activeSection, setActiveSection] = useState('');

  useEffect(() => {
    const handleScroll = () => {
      const sections = ['product', 'how-it-works', 'security'];

      // Determine which section is currently active
      // We look for the section that covers the top part of the viewport
      let current = '';

      for (const section of sections) {
        const element = document.getElementById(section);
        if (element) {
          // 120px offset to trigger slightly before the section hits the top
          // This aligns with the visual feel of "entering" the section
          if (window.scrollY >= (element.offsetTop - 120)) {
            current = section;
          }
        }
      }

      setActiveSection(current);
    };

    window.addEventListener('scroll', handleScroll);
    // Trigger once on mount to set initial state
    handleScroll();

    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const getLinkClasses = (section: string) => {
    return `text-sm font-medium transition-colors ${
      activeSection === section 
        ? 'text-black' 
        : 'text-gray-500 hover:text-black'
    }`;
  };

  return (
    <nav className="fixed top-0 w-full z-50 bg-white/95 backdrop-blur-sm border-b border-gray-100 transition-all duration-300">
      <div className="max-w-5xl mx-auto px-6 h-16 flex items-center justify-between">
        <div className="flex items-center gap-2.5">
          <Search className="w-5 h-5 text-black" strokeWidth={2.5} />
          <span className="font-semibold text-gray-900 tracking-tight text-lg">OpenScientific</span>
        </div>

        <div className="flex items-center gap-6 md:gap-8">
          <div className="hidden md:flex items-center gap-6">
            <a 
              href="#product" 
              className={getLinkClasses('product')}
            >
              Product
            </a>
            <a 
              href="#how-it-works" 
              className={getLinkClasses('how-it-works')}
            >
              How it works
            </a>
            <a 
              href="#security" 
              className={getLinkClasses('security')}
            >
              Security
            </a>
            <a href="#" className="text-sm font-medium text-gray-500 hover:text-black transition-colors">FAQ</a>
          </div>
          <a href="#waitlist" className="text-sm font-medium text-white bg-black hover:bg-gray-800 px-4 py-2 rounded-full transition-all active:scale-95">
            Join waitlist
          </a>
        </div>
      </div>
    </nav>
  );
};
